def assess(record: dict) -> str:
    required_fields = {"case_id", "lock_copied_before_source", "dependency_layer_reused", "source_change_rebuilds", "digest_stable"}
    absent = sorted(required_fields - set(record))
    if absent:
        return "MISSING:" + ",".join(absent)
    ok = not (not record["dependency_layer_reused"] and record["source_change_rebuilds"] > 3)
    return "PASS" if ok else "REORDER_DOCKERFILE"

valid = {"case_id": "CASO-TRU-043-1A", **{"lock_copied_before_source": True, "dependency_layer_reused": True, "source_change_rebuilds": 1, "digest_stable": True}}
invalid = {"case_id": "CASO-TRU-043-1A", **{"lock_copied_before_source": True, "dependency_layer_reused": False, "source_change_rebuilds": 999, "digest_stable": True}}
incomplete = dict(valid)
if "digest_stable" in incomplete:
    del incomplete["digest_stable"]
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

